'use strict';

const CONFIG = {
  VERSION: '4.1',
  TOTAL_AGENTS: 600,
  ACTIVE_PER_SHIFT: 200,
  TIERS: {
    STRATEGY: { count: 20, weight: 3.0, role: 'high-stakes governance' },
    EXECUTION: { count: 60, weight: 1.5, role: 'task coordination' },
    WORKER: { count: 120, weight: 1.0, role: 'parallel execution' }
  },
