  TARGET_LATENCY_MS: 35,
  ATP_519: {
    RISK_CATEGORIES: ['A', 'B', 'C', 'D', 'E'],
    SEVERITY_LEVELS: ['I', 'II', 'III', 'IV'],
    RISK_MATRIX: {
      // Risk Category × Severity → Risk Level
      'A-I': 'EH', 'A-II': 'EH', 'A-III': 'H', 'A-IV': 'M',
      'B-I': 'EH', 'B-II': 'H', 'B-III': 'M', 'B-IV': 'L',
