      'D-I': 'M', 'D-II': 'M', 'D-III': 'L', 'D-IV': 'L',
      'E-I': 'M', 'E-II': 'L', 'E-III': 'L', 'E-IV': 'L'
    }
  }
};

/**
 * Deterministic hash for agent selection.
 * Same seed always produces same agent set.
 * @param {string} seed - Shift seed string
 * @returns {number} - Hash value
 */
function deterministicHash(seed) {
  let hash = 0;
  for (let i = 0; i < seed.length; i++) {
    hash = ((hash << 5) - hash) + seed.charCodeAt(i);
    hash |= 0; // Convert to 32-bit integer
  }
  return Math.abs(hash);
}

/**
 * Select active agents for this shift.
 * @param {string} shiftSeed - Seed for deterministic selection
 * @returns {Array} - Array of active agent objects
 */
function selectActiveAgents(shiftSeed) {
  const hash = deterministicHash(shiftSeed);
  const agents = [];

  // Select from each tier proportionally
  for (const [tier, config] of Object.entries(CONFIG.TIERS)) {
    const startIdx = hash % Math.floor(CONFIG.TOTAL_AGENTS / 3);
    for (let i = 0; i < config.count; i++) {
      agents.push({
        id: `${tier.toLowerCase()}_${(startIdx + i) % CONFIG.TOTAL_AGENTS}`,
        tier,
        weight: config.weight,
        role: config.role
      });
    }
  }

  return agents.slice(0, CONFIG.ACTIVE_PER_SHIFT);
}

