 * Analyzes content for risk category (A-E).
 * @param {string} content - Content to analyze
 * @returns {string} - Risk category A-E
 */
function detectRisk(content) {
  if (!content || typeof content !== 'string') return 'E';

  const riskPatterns = {
    A: /\b(catastrophic|death|fatal|system.?loss|total.?failure|irreversible)\b/i,
    B: /\b(severe|critical.?injury|major.?damage|significant.?harm)\b/i,
    C: /\b(moderate|substantial|considerable|notable.?impact)\b/i,
    D: /\b(minor|limited|small|low.?impact)\b/i,
    E: /\b(negligible|minimal|trivial|inconsequential)\b/i
  };

  for (const [category, pattern] of Object.entries(riskPatterns)) {
    if (pattern.test(content)) {
      return category;
    }
  }
  return 'E'; // Default to lowest risk
}

/**
 * Detect severity level from content (I-IV).
 * @param {string} content - Content to analyze
 * @returns {string} - Severity level I-IV
 */
function detectSeverity(content) {
  if (!content || typeof content !== 'string') return 'IV';

  const severityPatterns = {
    I: /\b(catastrophic|death|permanent|system.?loss)\b/i,
    II: /\b(critical|severe|major|serious)\b/i,
    III: /\b(marginal|moderate|significant)\b/i,
    IV: /\b(negligible|minor|low|minimal)\b/i
  };

  for (const [level, pattern] of Object.entries(severityPatterns)) {
    if (pattern.test(content)) {
      return level;
    }
  }
  return 'IV';
}

